python3 -c "
import json
# Look specifically for Beirut strikes, Oslo embassy, Israel Lebanon
for day in range(3, 7):
    fname = f'articles/2026/03/{day:02d}/articles.jsonl'
    try:
        with open(fname) as f:
            for line in f:
                art = json.loads(line)
                title = (art.get('title','') or '').lower()
                if 'oslo' in title and ('bomb' in title or 'blast' in title or 'embassy' in title or 'embass' in title):
                    print(f'[Mar {day}] OSLO: {(art.get(\"title\",\"\") or \"\")[:140]}')
                if 'beirut' in title and ('strike' in title or 'raid' in title or 'attack' in title or 'hit' in title):
                    print(f'[Mar {day}] BEIRUT: {(art.get(\"title\",\"\") or \"\")[:140]}')
    except FileNotFoundError:
        pass
" 2>/dev/null | head -15
